import{_ as e,o,c,R as t}from"./chunks/framework.O97JKVSI.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"about.md","filePath":"about.md","lastUpdated":1698214676000}'),a={name:"about.md"},d=t('<h3 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h3><p>本人小前端一枚，坐标南宁。多年前端开发经验，熟悉<code>jQuery</code>、<code>bootstrap</code>、<code>Vue</code>、<code>vuex</code>、<code>vue-router</code>、<code>element-ui</code>、<code>Vant</code>、<code>React</code>、<code>React Native</code>、<code>Ant Design</code>、<code>Taro</code>、<code>uni-app</code>、<code>uView</code>、小程序等常用前端框架和技术。熟悉的 NodeJS 后端技术框架有<code>Express</code>、<code>Koa</code>、<code>NestJS</code>。以前还用过一段时间的 PHP，但最近两年没怎么用了</p><p>目前主力开发语言的是 TypeScript，但闲暇时也会研究一下 Python、Golang、Docker 等</p><p>以前从事过企业的网管工作，后来转行做专职前端了。对运维有一定了解，比如 Docker 和 Linux 系统也能使用</p><p>这个笔记博客的创建初衷是记录多年的自学前端、后端和服务器运维相关技术的积累，方便以后查看，也方便自己复习，希望对大家有所帮助</p><p>联系我：<a href="mailto:334059075@qq.com" target="_blank" rel="noreferrer">334059075@qq.com</a></p>',6),r=[d];function n(s,p,_,i,u,l){return o(),c("div",null,r)}const f=e(a,[["render",n]]);export{h as __pageData,f as default};
